(function () {
    var content = execution.getVariables();
    var requestId = content.get('id');
    var requestObj = openidm.action('iga/governance/requests/' + requestId, 'GET', {}, {});
    var approverEmail = requestObj.request.custom.approverEmail;

    logger.error('aaronPOC: looking up approver by email: ' + approverEmail);

    var result = [];
    try {
        var queryResult = openidm.query('managed/alpha_user', {
            '_queryFilter': '/mail eq "' + approverEmail + '"'
        });
        if (queryResult && queryResult.result && queryResult.result.length > 0) {
            var user = queryResult.result[0];
            result.push({
                'id': 'managed/user/' + user._id,
                'permissions': {
                    'approve': true,
                    'reject': true,
                    'reassign': true,
                    'modify': false,
                    'comment': true
                }
            });
            logger.error('aaronPOC: found approver: ' + user._id);
        } else {
            logger.error('aaronPOC: no user found for email: ' + approverEmail);
        }
    } catch (e) {
        logger.error('aaronPOC: actor lookup failed: ' + e);
    }
    return result;
})()
